import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";

export interface StudentAttendance {
  name: string;
  status: string;
}

export interface CourseInfo {
  curso: string;
  turma: string;
  componenteCurricular: string;
  periodo: string;
  cargaHoraria: string;
  mediador: string;
  poloMunicipio: string;
}

/**
 * 🔥 LOGO PROFISSIONAL (BASE64 FIXO)
 * - não depende de Vite
 * - não depende de path
 * - não quebra em produção
 */
const logoBase64 =
  "data:image/jpeg;base64,";

/**
 * (Opcional) helper de cores hex → RGB
 */
const hexToRgb = (hex: string) => {
  const clean = hex.replace("#", "");
  return {
    r: parseInt(clean.substring(0, 2), 16),
    g: parseInt(clean.substring(2, 4), 16),
    b: parseInt(clean.substring(4, 6), 16),
  };
};

export async function generateAttendancePDF(
  date: string,
  description: string,
  students: StudentAttendance[],
  courseInfo: CourseInfo
) {
  const doc = new jsPDF("p", "mm", "a4");

  const pageWidth = doc.internal.pageSize.getWidth();
  const pageHeight = doc.internal.pageSize.getHeight();

  const primary = hexToRgb("#00873E");

  // =========================
  // HEADER PROFISSIONAL
  // =========================
  const headerHeight = 35;
  const barHeight = 14;

  const logoWidth = 70;
  const logoHeight = 28;

  const logoX = (pageWidth - logoWidth) / 2;

  // =========================
  // FUNDO BRANCO (HEADER)
  // =========================
  doc.setFillColor(255, 255, 255);
  doc.rect(0, 0, pageWidth, headerHeight, "F");

  // =========================
  // LOGO CENTRALIZADA
  // =========================
  doc.addImage(logoBase64, "PNG", logoX, 6, logoWidth, logoHeight);

  // =========================
  // BARRA VERDE INFERIOR
  // =========================
  doc.setFillColor(primary.r, primary.g, primary.b);
  doc.rect(0, headerHeight, pageWidth, barHeight, "F");

  // =========================
  // TÍTULO CENTRALIZADO
  // =========================
  doc.setFont("helvetica", "bold");
  doc.setFontSize(18);
  doc.setTextColor(255, 255, 255);

  doc.text("CONTROLE DE FREQUÊNCIA", pageWidth / 2, headerHeight + 9, {
    align: "center",
  });

  let y = 58;

  // =========================
  // CARD BUILDER
  // =========================
  const drawCard = (
    x: number,
    y: number,
    w: number,
    h: number,
    label: string,
    value: string
  ) => {
    doc.setFillColor(248, 250, 252);
    doc.setDrawColor(220, 220, 220);
    doc.roundedRect(x, y, w, h, 2, 2, "FD");

    doc.setFontSize(8);
    doc.setTextColor(120);
    doc.setFont("helvetica", "bold");
    doc.text(label.toUpperCase(), x + 3, y + 5);

    doc.setFont("helvetica", "normal");
    doc.setTextColor(30);
    doc.setFontSize(10);

    const lines = doc.splitTextToSize(value, w - 6);
    doc.text(lines, x + 3, y + 11);
  };

  const margin = 10;
  const cardW = (pageWidth - margin * 2 - 4) / 2;

  // =========================
  // INFO GRID
  // =========================
  drawCard(margin, y, cardW, 18, "Curso", courseInfo.curso);
  drawCard(margin + cardW + 4, y, cardW, 18, "Turma", courseInfo.turma);
  y += 22;

  drawCard(margin, y, cardW, 18, "Período", courseInfo.periodo);
  drawCard(
    margin + cardW + 4,
    y,
    cardW,
    18,
    "Carga Horária",
    courseInfo.cargaHoraria
  );
  y += 22;

  drawCard(
    margin,
    y,
    pageWidth - margin * 2,
    18,
    "Componente Curricular",
    courseInfo.componenteCurricular
  );
  y += 22;

  drawCard(
    margin,
    y,
    pageWidth - margin * 2,
    18,
    "Polo / Município",
    courseInfo.poloMunicipio
  );
  y += 25;

  drawCard(
    margin,
    y,
    pageWidth - margin * 2,
    28,
    "Dados do Encontro",
    `Data: ${date}\n\n${description}`
  );

  y += 35;

  // =========================
  // TABLE (AUTO TABLE)
  // =========================
  autoTable(doc, {
    startY: y,
    head: [["Nº", "Aluno", "Situação"]],
    body: students.map((s, i) => [String(i + 1), s.name, s.status]),
    theme: "grid",
    headStyles: {
      fillColor: [primary.r, primary.g, primary.b],
      textColor: 255,
      halign: "center",
    },
    alternateRowStyles: {
      fillColor: [248, 250, 252],
    },
    columnStyles: {
      0: { cellWidth: 15, halign: "center" },
      1: { cellWidth: 120 },
      2: { cellWidth: 35, halign: "center" },
    },
  });

  // =========================
  // SIGNATURES
  // =========================
  const finalY = (doc as any).lastAutoTable.finalY + 25;

  doc.line(25, finalY, 85, finalY);
  doc.line(125, finalY, 185, finalY);

  doc.setFontSize(9);
  doc.text(courseInfo.mediador, 55, finalY + 6, { align: "center" });
  doc.text("Mediador Presencial", 55, finalY + 12, { align: "center" });

  doc.text("Coordenação", 155, finalY + 12, { align: "center" });

  // =========================
  // SAVE
  // =========================
  doc.save(`frequencia-${date}.pdf`);
}
